import java.util.*; class InsufficientBalanceException extends Exception{ InsufficientBalanceException(String m){ super(m);} } class BankAccount{ double balance=5000; void withdraw(double amount) throws InsufficientBalanceException{ if(amount<0) throw new IllegalArgumentException(); if(amount>balance) throw new InsufficientBalanceException("Insufficient balance!"); balance-=amount; System.out.println("Withdrawal successful, new balance: "+balance); }} public class BankTransactionSystem{ public static void main(String[] args){ Scanner sc=new Scanner(System.in); double amount=sc.nextDouble(); BankAccount acc=new BankAccount(); try{ acc.withdraw(amount); }catch(InsufficientBalanceException e){ System.out.println("Insufficient balance!"); }catch(IllegalArgumentException e){ System.out.println("Invalid amount!"); } }}